mapper.select:
select form_id as formId, form_key as formKey, form_name as formName, schema_json as schemaJson, layout_json as layoutJson, disabled_flag as disabledFlag, remark, create_time as createTime, update_time as updateTime from t_bpm_form where deleted_flag = #{queryForm.deletedFlag}
and form_key like concat('%', #{queryForm.formKey}, '%')
and form_name like concat('%', #{queryForm.formName}, '%')
and disabled_flag = #{queryForm.disabledFlag}
order by update_time desc, form_id desc

select *
from t_bpm_form
where 1 = 1

    and form_id = #{formId}


    and form_key = #{formKey}


    and deleted_flag = #{deletedFlag}

limit 1
